import java.util.Arrays;

public int maxBeauty(int[] flowers, int newFlowers, int target, int full, int partial) {
    int beauty = 0;
    for (int f : flowers)
        beauty += (f >= target) ? full : partial * f;

    Arrays.sort(flowers);

    for (int i = 0; i < flowers.length && newFlowers > 0; ++i) {
        int needed = target - flowers[i];
        if (needed <= newFlowers) {
            beauty += full - partial * flowers[i];
            flowers[i] = target;
            newFlowers -= needed;
        }
    }

    return beauty;
}
```

